const Q_BIOLOGY_2013=[{"id": "objective>Biology>2013>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which subject are you doing? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Biology </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chemistry  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">English   </div>", "<div style=\"font-family:Cambria;font-size:17px;\">History </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The question is asking about the subject being done. Since the questions are from a Biology exam, the correct answer is 'Biology'.</div>", "topic": "LIVING ORGANISMS : CHARACTERISTICS"}, {"id": "objective>Biology>2013>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The process in which complex substances are broken down into simpler ones is referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">metabolism </div>", "<div style=\"font-family:Cambria;font-size:17px;\">tropism </div>", "<div style=\"font-family:Cambria;font-size:17px;\">anabolism </div>", "<div style=\"font-family:Cambria;font-size:17px;\">catabolism</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The process in which complex substances are broken down into simpler ones is referred to as 'catabolism'. This is a type of metabolic process that breaks down molecules into smaller units to release energy. 'Metabolism' is a broad term that includes all chemical reactions that occur within an organism, including both anabolism (building up) and catabolism (breaking down). 'Tropism' is a biological phenomenon indicating growth or turning movement of a biological organism in response to an environmental stimulus. 'Anabolism' is the process in which simpler substances are converted into complex ones.</div>", "topic": "NUTRITION : ANIMAL NUTRITION"}, {"id": "objective>Biology>2013>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The organ which is sensitive to light in Euglena is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">chloroplast </div>", "<div style=\"font-family:Cambria;font-size:17px;\">eyespot </div>", "<div style=\"font-family:Cambria;font-size:17px;\">gullet </div>", "<div style=\"font-family:Cambria;font-size:17px;\">flagellum</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The organ which is sensitive to light in Euglena is the 'eyespot'. The eyespot, or stigma, is a photoreceptive organelle found in the flagellate protists such as Euglena. It allows the cell to sense light direction and intensity and respond by swimming either towards the light (positive phototaxis) or away from it (negative phototaxis). 'Chloroplast' is an organelle within the cells of plants and certain algae that is the site of photosynthesis, which is the process by which light energy is converted to chemical energy, resulting in the production of oxygen and energy-rich organic compounds. 'Gullet' is the passage by which food passes from the mouth to the stomach. 'Flagellum' is a lash-like appendage that protrudes from the cell body of certain bacteria and eukaryotic cells.</div>", "topic": "COORDINATION AND CONTROL : THE SENSE ORGANS"}, {"id": "objective>Biology>2013>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The organelles present in cells that are actively respiring and photosynthesizing are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Nucleus and centrioles </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mitochondria and chloroplast  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lysosomes and ribosomes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Golgi apparatus and endoplasmic reticulum  </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mitochondria and chloroplasts are the organelles present in cells that are actively respiring and photosynthesizing. Mitochondria are the powerhouses of the cell, where respiration occurs to produce energy. Chloroplasts are found in plant cells and are where photosynthesis occurs to convert light energy into chemical energy.</div>", "topic": "LIVING ORGANISMS : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS"}, {"id": "objective>Biology>2013>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Taenia solium can be found in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dog </div>", "<div style=\"font-family:Cambria;font-size:17px;\">pig </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cow </div>", "<div style=\"font-family:Cambria;font-size:17px;\">goat</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Taenia solium, also known as the pork tapeworm, can be found in pigs. Humans can get infected by eating undercooked pork that contains the larvae of the tapeworm.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>2013>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question that follows  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The structure labeled II is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">clitellum </div>", "<div style=\"font-family:Cambria;font-size:17px;\">chaetae </div>", "<div style=\"font-family:Cambria;font-size:17px;\">spermathecal pore </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cocoon</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The clitellum is an organ used for sexual reproduction of some annelids</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2013>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer the question that follows  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The organism is found in soils rich in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">clay </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sand </div>", "<div style=\"font-family:Cambria;font-size:17px;\">mud </div>", "<div style=\"font-family:Cambria;font-size:17px;\">humus</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The organism is found in soils rich in humus. Earthworms are found in moist soil rich in humus.</div>", "topic": "SOIL : CHARACTERISTICS OF DIFFERENT TYPES OF SOIL"}, {"id": "objective>Biology>2013>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following describes a characteristic of arthropods? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The body is not divided into a number of segments </div>", "<div style=\"font-family:Cambria;font-size:17px;\">The body is covered by chitin </div>", "<div style=\"font-family:Cambria;font-size:17px;\">The organism finds it easy to grow freely </div>", "<div style=\"font-family:Cambria;font-size:17px;\">The organism has a pair of jointed appendages  </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Arthropods are characterized by having bodies covered by chitin. Chitin is a tough, protective, semitransparent substance, primarily a nitrogen-containing polysaccharide, forming the principal component of arthropod exoskeletons and the cell walls of certain fungi.</div>", "topic": "LIVING ORGANISMS : CHARACTERISTICS"}, {"id": "objective>Biology>2013>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following distinguishes a butterfly from a moth? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">They have similar antennae </div>", "<div style=\"font-family:Cambria;font-size:17px;\">The abdomen of moth is fatter than that of butterfly  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">The wings of butterfly rest horizontally but those of moth rest vertically </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Both are active during the day  </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Butterflies and moths both possess a pair of wings; while butterflies are diurnal insects, most moths are nocturnal. They differ from butterflies as they have fatter and more hairy bodies. The antennae of most moths are pointed at their tips while those of most butterflies have knobs at their tips. At rest, the wings of most moths are spread out horizontally while those of most butterflies are held vertically. The fore and hind wings of a moth are connected to each other while those of a butterfly are not. The pupae of a moth are generally enclosed in well-developed cocoons while those of butterflies are not. Most butterflies are bright-coloured while moths tend to have dull colouring</div>", "topic": "STRUCTURAL/BEHAVIOURAL ADAPTATIONS OF VERTEBRATES : BIRD"}, {"id": "objective>Biology>2013>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following types of feathers is used for flight in birds? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Covert </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Down </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Quill </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Filoplume   </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Birds have different types of feathers, each serving a specific function. The quill or flight feathers are the long, stiff feathers that are used for flight and steering. They are attached to the wing and tail. Covert feathers are small feathers that cover the bases of the larger flight feathers. Down feathers are the soft, fluffy feathers located beneath the outer feathers that provide insulation. Filoplume feathers are hair-like feathers that have sensory functions.</div>", "topic": "STRUCTURAL/BEHAVIOURAL ADAPTATIONS OF VERTEBRATES : BIRD"}, {"id": "objective>Biology>2013>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The plants that grow in deserts or very dry areas are referred to as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">epiphytes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">xerophytes  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">mesophytes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrophytes </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Plants that grow in deserts or very dry areas are referred to as xerophytes. Xerophytes have adapted to survive in an environment with little water. They have features such as thick cuticles, reduced leaf areas, sunken stomata and the presence of a large number of stomata on their stems to reduce water loss. Epiphytes are plants that grow on other plants but are not parasitic, such as the numerous ferns, bromeliads, air plants, and orchids growing on tree trunks in rainforests. Mesophytes are plants that require a more or less balanced supply of water. They neither very dry not very wet conditions. Hydrophytes are plants that have adapted to living in aquatic environments.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>2013>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is the simplest living organism? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Amoeba </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chlamydomonas </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Paramacium  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Virus  </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The simplest living organism is a virus. A virus is a small infectious agent that replicates only inside the living cells of an organism. Viruses can infect all types of life forms, from animals and plants to microorganisms, including bacteria and archaea.</div>", "topic": "LIVING ORGANISMS : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS"}, {"id": "objective>Biology>2013>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Proboscis is a structure that is mostly found in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Amphibians </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Molluscs </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Insects </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tapeworms</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A proboscis is an elongated appendage from the head of an animal. The most well-known example of a proboscis in insects is the feeding tube used by nectar-feeding insects such as butterflies and moths.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2013>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The structural adaptation of desert plants for water conservation is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Spiny leaves </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Prominent stomata in leaves </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Broad leaves with numerous stomata </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Spongy mesophyll  </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Desert plants have adapted to the extremes of heat and aridity by using both physical and behavioral mechanisms. One of the physical mechanisms is having spiny leaves which reduce the surface area that would otherwise be exposed to the hot sun and thus reduce water loss.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>2013>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The long and sharp clawed feet of birds is an adaptation for </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Tearing flesh </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Grasping prey </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Crushing seeds </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Scooping mud</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The long and sharp clawed feet of birds are an adaptation for grasping prey. This is especially true for birds of prey, such as hawks and eagles, which use their powerful talons to catch and hold onto their prey. The claws are not primarily used for tearing flesh, crushing seeds, or scooping mud.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2013>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">During the manufacture of food by plants, which of the following organisms use energy from the sun? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Nitrosomonas sp. </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nitrobacter sp. </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Anabaena </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sulfur bacteria  </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Anabaena is a type of cyanobacteria that uses energy from the sun to manufacture food through the process of photosynthesis. Cyanobacteria are a group of photosynthetic bacteria, some of which are nitrogen-fixing, that live in a wide variety of moist soils and water either freely or in a symbiotic relationship with plants or lichen.</div>", "topic": "NUTRITION : PHOTOSYNTHESIS"}, {"id": "objective>Biology>2013>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Movement of minerals and chemical compounds within a plant occurs during </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Transpiration </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Diffusion </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Osmosis </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Translocation</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Movement of minerals and chemical compounds within a plant occurs during translocation. Translocation is the process by which organic substances move through the phloem of a plant. This process allows the plant to distribute the nutrients it produces during photosynthesis to all parts of the plant. Transpiration, diffusion, and osmosis are all involved in the movement of water and other substances in plants, but they do not specifically involve the movement of minerals and chemical compounds.</div>", "topic": "TRANSPORT : MATERIALS FOR TRANSPORTATION"}, {"id": "objective>Biology>2013>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The enzyme that is present in the saliva is  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Pepsin </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ptyalin </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rennin </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lipase</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The enzyme present in saliva is Ptyalin, also known as salivary amylase. It begins the process of digestion of food by breaking down starch into maltose, a smaller carbohydrate.</div>", "topic": "NUTRITION : ANIMAL NUTRITION"}, {"id": "objective>Biology>2013>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Plants that have special devices for trapping and digesting insects are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Parasitic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Saprophytic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Carnivorous </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Symbiotic </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Carnivorous plants have special devices for trapping and digesting insects. They live in environments where the soil is low in nutrients, especially nitrogen, such as acidic bogs and rock outcroppings. Examples of carnivorous plants include the Venus flytrap, pitcher plant, and sundew.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2013>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The process of transforming the chemical energy of cellular fuels into the high energy bonds of ATP in plants is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Photolysis </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Respiration </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Autotrophism </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Photosynthesis</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The process of transforming the chemical energy of cellular fuels into the high energy bonds of ATP in plants is Respiration. ATP (Adenosine triphosphate) is a complex organic chemical that provides energy to drive many processes in living cells, such as muscle contraction, nerve impulse propagation, and chemical synthesis. Respiration is the process by which cells obtain energy from glucose. During respiration, cells break down simple food molecules, such as sugar, and release the energy they contain.</div>", "topic": "RESPIRATION : AEROBIC RESPIRATION"}, {"id": "objective>Biology>2013>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Fungi are referred to as heterotrophs because they </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Have mycelium </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lack roots </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Are filamentous </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lack chlorophyll </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fungi are referred to as heterotrophs because they lack chlorophyll. Heterotrophs are organisms that cannot manufacture their own food and instead obtain their food from other organisms. Because fungi lack chlorophyll, they cannot perform photosynthesis and therefore must obtain nutrients from other sources.</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : FUNGI"}, {"id": "objective>Biology>2013>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of a parasitic protozoan is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Euglena </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chlamydomonas </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Paramecium </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Plasmodium </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Plasmodium is an example of a parasitic protozoan. It is the causative agent of malaria, a disease transmitted to humans through the bite of an infected mosquito. The other options, Euglena, Chlamydomonas, and Paramecium, are not parasitic protozoans.</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : PROTISTA"}, {"id": "objective>Biology>2013>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which blood cells are involved in the immune response of vertebrates? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Erythrocytes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Monocytes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Phagocytes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lymphocytes</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lymphocytes are the blood cells involved in the immune response of vertebrates. They are a type of white blood cell that is part of the immune system. There are two main types of lymphocytes: B cells, which produce antibodies that are used to attack invading bacteria, viruses, and toxins; and T cells, which attack the body's own cells that have been taken over by viruses or become cancerous.</div>", "topic": "HUMANS AND ENVIRONMENT : DISEASES"}, {"id": "objective>Biology>2013>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The blood circulatory system of vertebrates consists of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Heart, aorta, arteries and veins </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Heart, vena cava, arteries and veins </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Heart, arteries, capillaries and veins </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Heart, aorta, capillaries and veins  </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The blood circulatory system of vertebrates consists of the heart, arteries, capillaries, and veins. The heart pumps blood, arteries carry blood away from the heart, capillaries are where the exchange of nutrients and waste occurs, and veins carry blood back to the heart.</div>", "topic": "TRANSPORT : MAMMALIAN CIRCULATORY SYSTEM"}, {"id": "objective>Biology>2013>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A plant tissue that carries water and mineral salts is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Cortex </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Phloem </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cambium </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Xylem</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Xylem is a type of tissue in vascular plants that transports water and dissolved minerals from the roots to the rest of the plant. It is also involved in replacing water lost during transpiration and photosynthesis.</div>", "topic": "TRANSPORT : PLANT VASCULAR SYSTEM"}, {"id": "objective>Biology>2013>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following helps in the clotting of blood? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Plasma </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Platelets </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Red blood cells </div>", "<div style=\"font-family:Cambria;font-size:17px;\">White blood cells</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Platelets, also called thrombocytes, are blood cells that cause blood clots and other necessary growth healing functions. Platelets are the smallest of our blood cells, with a diameter of 2–3 µm and no nucleus. Their main function is to contribute to hemostasis: the process of stopping bleeding at the site of interrupted endothelium.</div>", "topic": "TRANSPORT : MAMMALIAN CIRCULATORY SYSTEM"}, {"id": "objective>Biology>2013>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following forms about 55% of the volumes of the blood in man? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Plasma </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Erythrocytes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Leucocytes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Platelets</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Plasma makes up about 55% of the blood's volume. Blood plasma is the liquid component of blood, in which the blood cells are suspended. It is a yellowish liquid that carries nutrients, hormones, and proteins throughout the body.</div>", "topic": "TRANSPORT : MAMMALIAN CIRCULATORY SYSTEM"}, {"id": "objective>Biology>2013>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The part of the mammalian skin involved in excretion is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sebaceous gland </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Horny gland  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sweat gland </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Malpighian layer</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The sweat gland in the mammalian skin is involved in excretion. It helps to regulate body temperature by secreting sweat, which evaporates and cools the body. It also helps to excrete waste products such as urea and salts.</div>", "topic": "EXCRETION : EXCRETORY MECHANISMS"}, {"id": "objective>Biology>2013>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a waste product of an insect? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sweat </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mucilage </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Alkaloids </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Uric acid </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Uric acid is a waste product of insects. Insects, like many other animals, produce waste products as a result of their metabolic processes. One of these waste products is uric acid, which is excreted from the body.</div>", "topic": "EXCRETION : EXCRETORY MECHANISMS"}, {"id": "objective>Biology>2013>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main structure in vertebrates that supports and protects the body is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Muscle </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Joint </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Skeleton </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ligament </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The skeleton is the main structure in vertebrates that supports and protects the body. It provides a framework that supports the body and allows for movement. It also protects the internal organs from injury.</div>", "topic": "SUPPORT AND MOVEMENT : TYPES AND FUNCTIONS OF THE SKELETON"}, {"id": "objective>Biology>2013>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The chitin in the exoskeleton of many arthropods is strengthened by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Calcium compounds </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Organic salts </div>", "<div style=\"font-family:Cambria;font-size:17px;\">lipids </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Proteins  </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The chitin in the exoskeleton of many arthropods is strengthened by calcium compounds. Chitin is a complex carbohydrate that provides rigidity and strength to the exoskeleton, and the addition of calcium compounds further hardens and strengthens this structure.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2013>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The transfer of pollen grains from the anther to a receptive stigma is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Pollination  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fertilization  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Propagation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Placentation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The transfer of pollen grains from the anther to a receptive stigma is called pollination. This is a crucial step in the reproductive process of flowering plants, allowing for the fertilization of the ovule and the production of seeds.</div>", "topic": "REPRODUCTION : SEXUAL REPRODUCTION"}, {"id": "objective>Biology>2013>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The male reproductive organ of a flower is the  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Petal </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sepal </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Carpel </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Stamen</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The stamen is the male reproductive organ of a flower. It consists of an anther, where pollen is produced, and a filament, which supports the anther.</div>", "topic": "REPRODUCTION : SEXUAL REPRODUCTION"}, {"id": "objective>Biology>2013>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The gland that is found just below the hypothalamus is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Pituitary </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Thyroid </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Parathyroid </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Adrenal</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The pituitary gland is a small pea-sized gland that plays a major role in regulating vital body functions and general wellbeing. It is referred to as the body's 'master gland' because it controls the activity of most other hormone-secreting glands.</div>", "topic": "COORDINATION AND CONTROL : HORMONAL CONTROL"}, {"id": "objective>Biology>2013>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most important plant hormone is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Auxin </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gibberellins </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cytokinin </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Abscisic acid</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Auxins are a class of plant hormones (or plant growth regulators) with some morphogen-like characteristics. Auxins have a cardinal role in coordination of many growth and behavioral processes in the plant's life cycle and are essential for plant body development.</div>", "topic": "COORDINATION AND CONTROL : HORMONAL CONTROL"}, {"id": "objective>Biology>2013>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The sensory cell that responds to dim light is referred to as the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rods </div>", "<div style=\"font-family:Cambria;font-size:17px;\">iris</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cone </div>", "<div style=\"font-family:Cambria;font-size:17px;\">lens  </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The sensory cells in the retina of the eye that are responsible for vision in dim light are called rods. They are more sensitive to light than cones, the other type of photoreceptor, which are responsible for color vision and detail.</div>", "topic": "COORDINATION AND CONTROL : THE SENSE ORGANS"}, {"id": "objective>Biology>2013>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The absence of anti-diuretic hormone in humans results in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Eliminating dehydration </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Increasing dehydration </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Decreasing dehydration </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Drastic dehydration  </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The anti-diuretic hormone (ADH) helps the kidneys manage the amount of water in your body. The absence of ADH causes a condition called diabetes insipidus, which causes frequent urination, leading to increased dehydration.</div>", "topic": "EXCRETION : EXCRETORY MECHANISMS"}, {"id": "objective>Biology>2013>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Oestrogen is a hormone that is synthesized in the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Anterior pituitary </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Adrenal cortex </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ovaries </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Testes</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Oestrogen is a hormone that is synthesized in the ovaries. It is responsible for the development and regulation of the female reproductive system and secondary sex characteristics.</div>", "topic": "COORDINATION AND CONTROL : HORMONAL CONTROL"}, {"id": "objective>Biology>2013>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The eye defect caused by the development of cloudy areas in the lenses is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Cataract</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Astigmatism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Presbyopia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Glaucoma</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cataract is an eye condition that occurs when the lens of the eye becomes cloudy, leading to blurry or less colorful vision. It is caused by the clumping of proteins in the eye's lens. Astigmatism, Presbyopia, and Glaucoma are other eye conditions but they are not caused by the development of cloudy areas in the lenses.</div>", "topic": "COORDINATION AND CONTROL : THE SENSE ORGANS"}, {"id": "objective>Biology>2013>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A pollutant that is biodegradable is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Cellophane </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sewage </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Crude oil </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Heavy metals </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Biodegradable pollutants are substances that can be broken down by natural processes, such as the action of bacteria. Sewage is an example of a biodegradable pollutant because it can be broken down by bacteria and other microorganisms. Cellophane, Crude oil, and Heavy metals are not easily broken down by natural processes, hence they are not biodegradable.</div>", "topic": "HUMANS AND ENVIRONMENT : POLLUTION AND ITS CONTROL"}, {"id": "objective>Biology>2013>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A tropical disease caused by Trypanosoma is  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Yellow fever </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Malaria </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sleeping sickness </div>", "<div style=\"font-family:Cambria;font-size:17px;\">River blindness  </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sleeping sickness, also known as African trypanosomiasis, is a tropical disease caused by the Trypanosoma parasite. This parasite is transmitted to humans through the bite of a tsetse fly. Yellow fever, Malaria, and River blindness are other tropical diseases but they are not caused by Trypanosoma.</div>", "topic": "HUMANS AND ENVIRONMENT : DISEASES"}, {"id": "objective>Biology>2013>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The solid part of the ecosystem is referred to as   </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Biosphere </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lithosphere </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Atmosphere </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hydrosphere</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The solid part of the ecosystem is referred to as the Lithosphere. The lithosphere is the rigid, outermost shell of a terrestrial-type planet or natural satellite that is defined by its rigid mechanical properties. It encompasses the crust and the portion of the upper mantle that behaves elastically on time scales of thousands of years or greater.</div>", "topic": "ECOLOGY : ENERGY FLOW IN THE ECOSYSTEM"}, {"id": "objective>Biology>2013>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is caused by <span style=\"font-style:italic;\"> Treponema palladium </span>? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Tuberculosis </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Syphilis </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gonorrhea </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Leprosy</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Syphilis is caused by the bacterium <span style=\"font-style:italic;\"> Treponema pallidum </span>. This bacterium is a spirochete, a class of long, slender bacteria that have a distinctive helical shape.</div>", "topic": "HUMANS AND ENVIRONMENT : DISEASES"}, {"id": "objective>Biology>2013>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">To which blood group do universal recipients belong? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">O </div>", "<div style=\"font-family:Cambria;font-size:17px;\">AB </div>", "<div style=\"font-family:Cambria;font-size:17px;\">B </div>", "<div style=\"font-family:Cambria;font-size:17px;\">A </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Universal recipients belong to the AB blood group. This is because they have both A and B antigens on the surface of their red blood cells, and their blood serum does not contain any antibodies against these antigens. Therefore, they can receive blood from donors of any blood type: A, B, AB, or O.</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>2013>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The clumping together of red blood cells is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Transfusion </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Compatibility </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Agglutination </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fusion</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The clumping together of red blood cells is known as Agglutination. This usually occurs when there is a reaction between an antigen and its corresponding antibody.</div>", "topic": "TRANSPORT : MATERIALS FOR TRANSPORTATION"}, {"id": "objective>Biology>2013>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Physiological adaptation to very dry condition in animals demonstrates </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Hibernation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Aestivation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rejuvenation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Xeromorphism</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Physiological adaptation to very dry conditions in animals demonstrates Aestivation. Aestivation, also known as estivation, is a state of animal dormancy, similar to hibernation, characterized by inactivity and a lowered metabolic rate, that is entered in response to high temperatures and arid conditions.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>2013>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One adaptation of <span style=\"font-style:italic;\"> Cactus opuntia </span>to conserve water is the reduction of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Leaves to spine </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Flower size </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Internodes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Stem to leaves </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One adaptation of <span style=\"font-style:italic;\"> Cactus opuntia </span>to conserve water is the reduction of Leaves to spine. This is because the leaves of cacti are modified into spines, which are less likely to lose water than regular leaves. The spines also provide shade and protect the cactus from animals.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>2013>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following structures is adapted for feeding in a bird of prey? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Big beaks and strong feet </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pointed beak and strong claws </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hooked beak and sharp claws </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Smooth beak and strong claws  </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Birds of prey, also known as raptors, have a hooked beak and sharp claws, which are also known as talons. These adaptations help them to catch, kill and eat their prey. The hooked beak is used to tear the flesh of the prey, while the sharp claws are used to catch and hold the prey. It illustrates the beak and claw adaption of some bird of prey </div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2013>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The special pigment for colour change in chameleon is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Chromatin </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chromatophore </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Melanin </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Carotenoid</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Chromatophores are special pigment cells that are found in a wide range of animals including reptiles, fish, and cephalopods. They are responsible for skin color changes in animals such as chameleons. These cells can change the color of their skin by adjusting the positions of pigments within them, allowing the animal to blend in with its environment, communicate with others, or display emotions.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>2013>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The behavioural adaptation in social insects could best be described as  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Parasitism </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Commensalism </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Symbiosis  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Saprophytism</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The behavioural adaptation in social insects like ants, bees, wasps, and termites is best described as symbiosis. Symbiosis is a close and long-term biological interaction between two different biological organisms. In the context of social insects, this refers to the cooperative and mutually beneficial relationship within a colony, where different members perform different roles (like workers, soldiers, and reproducers) for the benefit of the whole colony.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}];
